38→            <input
39→              ref={inputRef}
40→              type="text"
41→              className="search-input"
42→              placeholder="Search entities..."
43→              value={query}
44→              onChange={(e) => setQuery(e.target.value)}
45→            />
46→          </div>
47→          <button type="button" className="search-overlay-close" onClick={onClose}>
48→            ✕
49→          </button>
50→        </div>
51→
52→        <SearchFilters activeFilter={activeFilter} onFilterChange={setActiveFilter} />
53→
54→        <div className="search-overlay-body">
55→          {!query.trim() ? (
56→            <div className="search-empty">
57→              <p>Type to search across decisions, tasks, features, and more.</p>
58→            </div>
59→          ) : isSearching ? (
60→            <div className="search-empty">
