302→export async function listConversationEntities(input: {
303→  surreal: Surreal;
304→  conversationRecord: RecordId<"conversation", string>;
305→  workspaceRecord: RecordId<"workspace", string>;
306→  limit: number;
307→  inheritedEntityIds?: RecordId[];
308→}): Promise<ConversationEntity[]> {
309→  const [rows] = await input.surreal
310→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
311→      [
312→        "SELECT `in`, out, confidence, extracted_at",
313→        "FROM extraction_relation",
314→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
315→        "ORDER BY extracted_at DESC",
316→        "LIMIT $limit;",
317→      ].join(" "),
318→      {
319→        conversation: input.conversationRecord,
320→        limit: input.limit,
321→      },
322→    )
323→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
324→
325→  const items: ConversationEntity[] = [];
326→  const seen = new Set<string>();
327→
328→  for (const row of rows) {
329→    const table = row.out.table.name as GraphEntityTable;
330→    if (
331→      table !== "workspace" &&
332→      table !== "project" &&
333→      table !== "person" &&
334→      table !== "feature" &&
335→      table !== "task" &&
336→      table !== "decision" &&
337→      table !== "question"
338→    ) {
339→      continue;
340→    }
341→
342→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
343→    if (!scoped) {
344→      continue;
345→    }
346→
347→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
348→    if (seen.has(entityKey)) {
349→      continue;
350→    }
351→
352→    const name = await readEntityName(input.surreal, row.out);
353→    if (!name) {
354→      continue;
355→    }
356→
357→    items.push({
358→      id: toRecordIdString(row.out),
359→      kind: table,
360→      name,
361→      confidence: row.confidence,
362→      sourceMessageId: toRecordIdString(row.in),
363→    });
364→    seen.add(entityKey);
365→  }
366→
367→  // Merge inherited entities from parent conversation when branch has sparse context
368→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
369→    const [inheritedRows] = await input.surreal
370→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
371→        [
372→          "SELECT `in`, out, confidence, extracted_at",
373→          "FROM extraction_relation",
374→          "WHERE out IN $entityIds",
375→          "ORDER BY extracted_at DESC",
376→          "LIMIT $limit;",
377→        ].join(" "),
378→        { entityIds: input.inheritedEntityIds, limit: input.limit },
379→      )
380→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
381→
382→    for (const row of inheritedRows) {
383→      const table = row.out.table.name as GraphEntityTable;
384→      if (
385→        table !== "workspace" &&
386→        table !== "project" &&
387→        table !== "person" &&
388→        table !== "feature" &&
389→        table !== "task" &&
390→        table !== "decision" &&
391→        table !== "question"
392→      ) {
393→        continue;
394→      }
395→
396→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
397→      if (seen.has(entityKey)) continue;
398→
399→      const name = await readEntityName(input.surreal, row.out);
400→      if (!name) continue;
401→
402→      items.push({
403→        id: toRecordIdString(row.out),
404→        kind: table,
405→        name,
406→        confidence: row.confidence,
407→        sourceMessageId: toRecordIdString(row.in),
408→      });
409→      seen.add(entityKey);
410→    }
411→  }
412→
